module simple_register (
    input clk,
    input reset,
    input enable,
    input [7:0] data_in,
    output reg [7:0] q
);

    // Register logic
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
        if (reset)
            q <= 8'b00000000;
        else if (enable)
            q <= data_in;
    end

endmodule
